1	/**
2	 * Layerinfinite — routes/audit.ts
3	 * GET /v1/audit
4	 * ══════════════════════════════════════════════════════════════
5	 * Immutable audit trail for compliance teams.
6	 * Returns a paginated list of logged outcomes (fact_outcomes)
7	 * with filtering by session, action, time range.
8	 * ALL data is read-only. No mutations possible.
9	 * GDPR: soft-deleted rows (is_deleted=TRUE) are excluded.
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const auditRouter = new Hono();
17	
18	const MAX_PAGE_SIZE = 100;
19	const DEFAULT_PAGE_SIZE = 50;
20	
21	// ── GET /v1/audit ─────────────────────────────────────────────
22	auditRouter.get('/', async (c) => {
23	    const customerId = c.get('customer_id') as string;
24	
25	    const sessionId = c.req.query('session_id');
26	    const actionName = c.req.query('action_name');
27	    const agentId = c.req.query('agent_id');
28	    const success = c.req.query('success');     // 'true' | 'false' | undefined
29	    const from = c.req.query('from');         // ISO date string
30	    const to = c.req.query('to');           // ISO date string
31	    const cursor = c.req.query('cursor');
32	    const pageStr = c.req.query('page');
33	    const offsetStr = c.req.query('offset');
34	    const sizeStr = c.req.query('page_size') ?? c.req.query('limit') ?? String(DEFAULT_PAGE_SIZE);
35	
36	    const page = Math.max(1, parseInt(pageStr ?? '1', 10) || 1);
37	    const pageSize = Math.min(MAX_PAGE_SIZE, Math.max(1, parseInt(sizeStr, 10) || DEFAULT_PAGE_SIZE));
38	
39	    // ── Build query ───────────────────────────────────────────
40	    let query = supabase
41	        .from('fact_outcomes')
42	        .select(`
43	      outcome_id,
44	      session_id,
45	      timestamp,
46	      success,
47	      response_time_ms,
48	      error_code,
49	      error_message,
50	      is_synthetic,
51	      salience_score,
52	      dim_agents!inner(agent_id, agent_name, agent_type),
53	      dim_actions!inner(action_id, action_name, action_category),
54	      dim_contexts!inner(context_id, issue_type, environment)
55	    `, { count: 'exact' })
56	        .eq('customer_id', customerId)
57	        .eq('is_deleted', false)           // GDPR: exclude soft-deleted
58	        .order('timestamp', { ascending: false })
59	        .order('outcome_id', { ascending: false })  // secondary sort: stable pagination across tied timestamps
60	        .limit(pageSize);
61	
62	    if (cursor) {
63	        try {
64	            const { ts, id } = JSON.parse(Buffer.from(cursor, 'base64').toString('utf-8'));
65	            // Validate before interpolation to prevent PostgREST filter injection.
66	            // ts must be an ISO 8601 timestamp; id must be a UUID.
67	            const ISO_TS = /^\d{4}-\d{2}-\d{2}T[\d:.]+(?:Z|[+-]\d{2}:\d{2})?$/;
68	            const UUID   = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
69	            if (typeof ts !== 'string' || typeof id !== 'string' || !ISO_TS.test(ts) || !UUID.test(id)) {
70	                throw new Error('invalid cursor shape');
71	            }
72	            // Composite row-value comparison (descending): skip rows at or before the cursor position.
73	            // Handles ties at page boundaries: same timestamp rows are ordered by outcome_id descending.
74	            query = query.or(`timestamp.lt.${ts},and(timestamp.eq.${ts},outcome_id.lt.${id})`);
75	        } catch {
76	            // Malformed or invalid cursor — ignore and return from the beginning
77	        }
78	    } else if (pageStr || offsetStr) {
79	        // Fallback for legacy offset pagination
80	        const offset = offsetStr ? parseInt(offsetStr, 10) : (page - 1) * pageSize;
81	        if (!isNaN(offset)) {
82	            query = query.range(offset, offset + pageSize - 1);
83	        }
84	    }
85	
86	    // ── Apply filters ─────────────────────────────────────────
87	    if (sessionId) query = query.eq('session_id', sessionId);
88	    if (agentId) query = query.eq('agent_id', agentId);
89	    if (success !== undefined) {
90	        query = query.eq('success', success === 'true');
91	    }
92	    if (from) query = query.gte('timestamp', from);
93	    if (to) query = query.lte('timestamp', to);
94	
95	    // Filter by action_name (via joined table)
96	    if (actionName) {
97	        // Supabase supports filtering on joined tables
98	        query = (query as any).eq('dim_actions.action_name', actionName);
99	    }
100	
101	    const { data, error, count } = await query;
102	
103	    if (error) {
104	        console.error('[audit] Query error:', error.message);
105	        return c.json({ error: 'Audit query failed', details: error.message, code: 'DB_ERROR' }, 500);
106	    }
107	
108	    const totalPages = Math.ceil((count ?? 0) / pageSize);
109	    // hasMore is true only when we filled a full page AND the DB has more rows beyond it.
110	    // Avoids false positives when total rows is an exact multiple of pageSize.
111	    const hasMore = (data?.length ?? 0) === pageSize && (count ?? 0) > (data?.length ?? 0);
112	    const lastRow = hasMore ? data![data!.length - 1] : null;
113	    const nextCursor = (lastRow?.timestamp && lastRow?.outcome_id)
114	        ? Buffer.from(JSON.stringify({ ts: lastRow.timestamp, id: lastRow.outcome_id })).toString('base64')
115	        : null;
116	
117	    return c.json({
118	        outcomes: (data ?? []).map((row: any) => ({
119	            outcome_id: row.outcome_id,
120	            session_id: row.session_id,
121	            timestamp: row.timestamp,
122	            success: row.success,
123	            response_time_ms: row.response_time_ms,
124	            error_code: row.error_code,
125	            error_message: row.error_message,
126	            is_synthetic: row.is_synthetic,
127	            salience_score: row.salience_score,
128	            agent: row.dim_agents ? {
129	                id: row.dim_agents.agent_id,
130	                name: row.dim_agents.agent_name,
131	                type: row.dim_agents.agent_type,
132	            } : null,
133	            action: row.dim_actions ? {
134	                id: row.dim_actions.action_id,
135	                name: row.dim_actions.action_name,
136	                category: row.dim_actions.action_category,
137	            } : null,
138	            context: row.dim_contexts ? {
139	                id: row.dim_contexts.context_id,
140	                issue_type: row.dim_contexts.issue_type,
141	                environment: row.dim_contexts.environment,
142	            } : null,
143	        })),
144	        pagination: {
145	            page,
146	            page_size: pageSize,
147	            total_rows: count ?? 0,
148	            total_pages: totalPages,
149	            has_next: page < totalPages,
150	            has_prev: page > 1,
151	            // Keyset fields
152	            next_cursor: nextCursor,
153	            has_more: hasMore,
154	        },
155	        pagination_warning: (pageStr || offsetStr) ? 'page/offset parameters deprecated. Use cursor.' : undefined,
156	        filters: {
157	            session_id: sessionId ?? null,
158	            action_name: actionName ?? null,
159	            agent_id: agentId ?? null,
160	            success: success ?? null,
161	            from: from ?? null,
162	            to: to ?? null,
163	        },
164	        note: 'This audit trail is immutable. All rows reflect append-only fact_outcomes.',
165	    });
166	});
167	
168	// ── GET /v1/audit/:outcome_id — Single outcome detail ─────────
169	auditRouter.get('/:outcome_id', async (c) => {
170	    const customerId = c.get('customer_id') as string;
171	    const outcomeId = c.req.param('outcome_id');
172	
173	    const { data, error } = await supabase
174	        .from('fact_outcomes')
175	        .select(`
176	      *,
177	      dim_agents!inner(agent_id, agent_name, agent_type, llm_model),
178	      dim_actions!inner(action_id, action_name, action_category, action_description),
179	      dim_contexts!inner(context_id, issue_type, environment, customer_tier)
180	    `)
181	        .eq('outcome_id', outcomeId)
182	        .eq('customer_id', customerId)
183	        .eq('is_deleted', false)
184	        .maybeSingle();
185	
186	    if (error) {
187	        return c.json({ error: 'Query failed', details: error.message }, 500);
188	    }
189	    if (!data) {
190	        return c.json({ error: `Outcome ${outcomeId} not found`, code: 'NOT_FOUND' }, 404);
191	    }
192	
193	    return c.json({ outcome: data });
194	});
195

1	/**
2	 * Layerinfinite — routes/get-scores.ts
3	 * GET /v1/get-scores
4	 * ══════════════════════════════════════════════════════════════
5	 * Returns ranked action scores for a given context.
6	 * Reads from mv_action_scores (never raw fact_outcomes).
7	 * Uses context-embed.ts for similarity matching.
8	 * Returns policy recommendation from policy engine.
9	 * ══════════════════════════════════════════════════════════════
10	 */
11	
12	import { Hono } from 'hono';
13	import crypto from 'node:crypto';
14	import { getScores, ScoredAction } from '../lib/scoring.js';
15	import { supabase } from '../lib/supabase.js';
16	import { bufferDecision } from '../lib/decision-writer.js';
17	import { generateEmbedding, findClosestContext, buildContextText } from '../lib/context-embed.js';
18	import {
19	    getPolicyDecision,
20	    DEFAULT_TRUST,
21	    DEFAULT_POLICY_CONFIG,
22	    AgentTrustScore,
23	    CustomerPolicyConfig,
24	} from '../lib/policy-engine.js';
25	import { computePropensities, RankedActionEntry } from '../lib/ips-engine.js';
26	
27	// ── Helper: fetch real agent trust from DB (falls back to DEFAULT_TRUST) ──
28	async function getAgentTrust(agentId: string | undefined): Promise<AgentTrustScore> {
29	    if (!agentId) return DEFAULT_TRUST;
30	    const { data, error } = await supabase
31	        .from('agent_trust_scores')
32	        .select('trust_score, trust_status, consecutive_failures')
33	        .eq('agent_id', agentId)
34	        .maybeSingle();
35	    if (error || !data) return DEFAULT_TRUST;
36	    return {
37	        trust_score: data.trust_score,
38	        trust_status: data.trust_status,
39	        consecutive_failures: data.consecutive_failures,
40	    };
41	}
42	
43	// ── Helper: fetch real customer config from DB (falls back to DEFAULT_POLICY_CONFIG) ──
44	async function getCustomerConfig(customerId: string): Promise<CustomerPolicyConfig> {
45	    const { data, error } = await supabase
46	        .from('dim_customers')
47	        .select('config')
48	        .eq('customer_id', customerId)
49	        .maybeSingle();
50	    if (error || !data?.config) return DEFAULT_POLICY_CONFIG;
51	    const cfg = data.config as Record<string, unknown>;
52	    return {
53	        risk_tolerance: (['conservative', 'balanced', 'aggressive'].includes(cfg.risk_tolerance as string)
54	            ? cfg.risk_tolerance : 'balanced') as CustomerPolicyConfig['risk_tolerance'],
55	        escalation_score: typeof cfg.escalation_score === 'number' ? cfg.escalation_score : 0.20,
56	        exploration_rate: typeof cfg.exploration_rate === 'number' ? cfg.exploration_rate : 0.05,
57	        min_confidence: typeof cfg.min_confidence === 'number' ? cfg.min_confidence : 0.30,
58	    };
59	}
60	
61	const STALE_THRESHOLD_MINUTES = 10;
62	
63	export const getScoresRouter = new Hono();
64	
65	// ── GET /v1/get-scores ────────────────────────────────────────
66	getScoresRouter.get('/', async (c) => {
67	    const customerId = c.get('customer_id') as string;
68	
69	    const agentId = c.get('agent_id') as string | undefined;
70	
71	    // ── Query params ──────────────────────────────────────────
72	    const issueType = c.req.query('issue_type');
73	    const contextId = c.req.query('context_id');
74	    const forceRefresh = c.req.query('refresh') === 'true';
75	    const topN = parseInt(c.req.query('top_n') ?? '10', 10);
76	
77	    // ── New optional params (backward compatible) ─────────────
78	    const episodeId = c.req.query('episode_id') ?? null;
79	    const episodeHistoryRaw = c.req.query('episode_history') ?? null;
80	    let episodeHistory: string[] | null = null;
81	    if (episodeHistoryRaw) {
82	        try {
83	            const parsed = JSON.parse(episodeHistoryRaw);
84	            if (Array.isArray(parsed)) episodeHistory = parsed;
85	        } catch {
86	            // Invalid JSON — ignore, treat as no history
87	        }
88	    }
89	
90	    // ── Fetch real trust + customer config in parallel ────────
91	    const [agentTrust, customerConfig] = await Promise.all([
92	        getAgentTrust(agentId),
93	        getCustomerConfig(customerId),
94	    ]);
95	
96	    if (!issueType && !contextId) {
97	        return c.json(
98	            { error: 'Provide either issue_type or context_id query parameter', code: 'MISSING_PARAM', agent_id: '', signal_contract: null },
99	            400
100	        );
101	    }
102	
103	    // ── Resolve context_id ───────────────────────────────────
104	    let resolvedContextId = contextId;
105	    let contextMatch: number | null = null;  // null = exact match
106	
107	    if (!resolvedContextId && issueType) {
108	        // Step 1: Try exact string match (fast path) — scoped to this customer
109	        const { data: exactCtx, error } = await supabase
110	            .from('dim_contexts')
111	            .select('context_id')
112	            .eq('customer_id', customerId)
113	            .eq('issue_type', issueType)
114	            .order('created_at', { ascending: false })
115	            .limit(1)
116	            .maybeSingle();
117	
118	        if (error) {
119	            return c.json({ error: 'Context lookup failed', details: error.message, code: 'DB_ERROR' }, 500);
120	        }
121	
122	        if (exactCtx) {
123	            resolvedContextId = exactCtx.context_id;
124	            contextMatch = null;  // exact match → treated as 1.0
125	        } else {
126	            // Step 2: Try embedding similarity (graceful fallback)
127	            try {
128	                const contextText = buildContextText(issueType);
129	                const embedding = await generateEmbedding(contextText);
130	
131	                if (embedding) {
132	                    const closest = await findClosestContext(embedding, customerId);
133	                    if (closest) {
134	                        resolvedContextId = closest.context_id;
135	                        contextMatch = closest.similarity;
136	                    }
137	                }
138	            } catch (err: any) {
139	                // Embedding failed — fall through to 404
140	                console.warn('[get-scores] Embedding fallback failed:', err.message);
141	            }
142	
143	            // If still no context found → cold start (200, not 404)
144	            if (!resolvedContextId) {
145	                return c.json({
146	                    ranked_actions:    [],
147	                    top_action:        null,
148	                    cold_start:        true,
149	                    context_id:        '',
150	                    agent_id:          agentId ?? '',
151	                    policy:            'explore',
152	                    policy_reason:     'No prior context — cold start active',
153	                    served_from_cache: false,
154	                    cold_start_warning: {
155	                        message:        `No context found for issue_type="${issueType}". Cold-start active.`,
156	                        recommendation: 'Log at least one outcome to seed this context.',
157	                    },
158	                    signal_contract: null,
159	                }, 200);
160	            }
161	        }
162	    }
163	
164	    // ── Fetch and score actions ───────────────────────────────
165	    try {
166	        const result = await getScores(
167	            customerId,
168	            resolvedContextId!,
169	            issueType ?? undefined,
170	            forceRefresh,
171	            contextMatch
172	        );
173	
174	        // Trim to top_n
175	        let ranked = result.ranked_actions.slice(0, Math.min(topN, 50));
176	
177	        // ── Deprioritize already-tried actions (CHANGE 4) ────
178	        if (episodeHistory && episodeHistory.length > 0) {
179	            ranked = ranked.map(action => {
180	                if (episodeHistory!.includes(action.action_name)) {
181	                    return {
182	                        ...action,
183	                        composite_score: action.composite_score * 0.3,
184	                        recommendation: 'avoid' as const,
185	                    };
186	                }
187	                return action;
188	            });
189	            // Re-sort after deprioritization
190	            ranked.sort((a, b) => b.composite_score - a.composite_score);
191	        }
192	
193	        // ── Context drift check (Gap 2) ──────────────────────
194	        const { count: contextOutcomeCount } = await supabase
195	            .from('mv_action_scores')
196	            .select('action_id', { count: 'exact', head: true })
197	            .eq('customer_id', customerId)
198	            .eq('context_id', resolvedContextId!);
199	
200	        const isUnknownContext = (contextOutcomeCount ?? 0) === 0;
201	
202	        // ── Compute propensities for ranked actions ──────────
203	        const propensityMap = computePropensities(
204	            ranked.map(a => ({ action_name: a.action_name, score: a.composite_score }))
205	        );
206	
207	        // Build ranked actions with propensities
208	        const rankedWithPropensity: RankedActionEntry[] = ranked.map((a, idx) => ({
209	            action_name: a.action_name,
210	            action_id: a.action_id,
211	            score: a.composite_score,
212	            rank: idx + 1,
213	            propensity: propensityMap.get(a.action_name) ?? 0,
214	        }));
215	
216	        // ── Create fact_decisions record (CHANGE 2) ──────────
217	        let decisionId: string | null = null;
218	        const contextHash = `${resolvedContextId}:${issueType ?? ''}`;
219	        const episodePosition = episodeHistory ? episodeHistory.length : 0;
220	        
221	        if (episodeId) {
222	            decisionId = bufferDecision({
223	                agent_id: agentId ?? null,
224	                context_id: resolvedContextId!,
225	                context_hash: contextHash,
226	                ranked_actions: rankedWithPropensity,
227	                episode_id: episodeId,
228	                episode_position: episodePosition,
229	            });
230	        }
231	
232	        // ── Sequence recommendation (CHANGE 3) ───────────────
233	        let recommendedSequence: {
234	            actions: string[];
235	            predicted_outcome: number;
236	            confidence: number;
237	            prediction_interval: [number, number];
238	            simulation_tier: 1 | 2 | 3;
239	            tier_explanation: string;
240	        } | null = null;
241	
242	        if (episodeHistory && episodeHistory.length > 0) {
243	            try {
244	                const { data: seqData } = await supabase
245	                    .from('mv_sequence_scores')
246	                    .select('*')
247	                    .eq('context_hash', contextHash)
248	                    .gte('sample_count', 3);
249	
250	                if (seqData && seqData.length > 0) {
251	                    // Find sequences that start with current episode history
252	                    const matching = seqData.filter((seq: any) => {
253	                        const seqActions: string[] = seq.action_sequence ?? [];
254	                        if (seqActions.length <= episodeHistory!.length) return false;
255	                        return episodeHistory!.every((a, i) => seqActions[i] === a);
256	                    });
257	
258	                    if (matching.length > 0) {
259	                        // Pick highest mean_outcome
260	                        const best = matching.reduce((a: any, b: any) =>
261	                            (b.mean_outcome ?? 0) > (a.mean_outcome ?? 0) ? b : a
262	                        );
263	                        recommendedSequence = {
264	                            actions: best.action_sequence,
265	                            predicted_outcome: best.mean_outcome ?? 0,
266	                            confidence: best.wilson_ci_lower ?? 0,
267	                            prediction_interval: [best.wilson_ci_lower ?? 0, best.wilson_ci_upper ?? 1],
268	                            simulation_tier: 1,
269	                            tier_explanation: 'Tier 1: Empirical sequence scores from observed data',
270	                        };
271	                    }
272	                }
273	            } catch (err: any) {
274	                console.warn('[get-scores] Sequence lookup failed:', err.message);
275	            }
276	        }
277	
278	        // ── Sequence context ─────────────────────────────────
279	        const sequenceContext = episodeHistory ? {
280	            episode_position: episodeHistory.length,
281	            actions_tried: episodeHistory,
282	            already_resolved: false,  // caller can check via episode state
283	        } : null;
284	
285	        // ── Policy recommendation ────────────────────────────
286	        const policy = getPolicyDecision({
287	            rankedActions: ranked,
288	            agentTrust: agentTrust,
289	            customerConfig: customerConfig,
290	            coldStartActive: result.cold_start,
291	        });
292	
293	        // ── Staleness signal ─────────────────────────────────
294	        const lastRefresh = result.view_refreshed_at ?? null;
295	        const ageMinutes = lastRefresh
296	            ? (Date.now() - new Date(lastRefresh).getTime()) / 60_000
297	            : null;
298	        const isStale = ageMinutes !== null && ageMinutes > STALE_THRESHOLD_MINUTES;
299	
300	        return c.json({
301	            ranked_actions: ranked,
302	            top_action: result.top_action,
303	            should_escalate: result.should_escalate,
304	            cold_start: result.cold_start,
305	            context_id: resolvedContextId,
306	            agent_id: agentId ?? '',
307	            customer_id: customerId,
308	            issue_type: issueType ?? null,
309	            context_match: contextMatch,
310	            context_warning: isUnknownContext ? {
311	                type: 'context_drift',
312	                message: 'No outcome history for this context type.',
313	                recommendation: 'Cold-start protocol active. Scores are based on priors only.',
314	                confidence_cap: 0.3,
315	            } : null,
316	            view_refreshed_at: result.view_refreshed_at,
317	            scores_as_of: result.view_refreshed_at,
318	            scores_max_age_seconds: 300,
319	            scoring_metadata: {
320	                view_refreshed_at: lastRefresh,
321	                is_stale: isStale,
322	                stale_threshold_minutes: STALE_THRESHOLD_MINUTES,
323	            },
324	            served_from_cache: result.served_from_cache,
325	            policy: policy.policy,
326	            policy_reason: policy.reason,
327	            agent_trust: {
328	                score: agentTrust.trust_score,
329	                status: agentTrust.trust_status,
330	            },
331	            meta: {
332	                total_actions_scored: result.ranked_actions.length,
333	                top_n_returned: ranked.length,
334	                scoring_version: '1.0',
335	            },
336	            // ── New fields (backward compatible — null when unused) ──
337	            decision_id: decisionId,
338	            recommended_sequence: recommendedSequence,
339	            sequence_context: sequenceContext,
340	            // ── Phase 1: Signal contract (always null until Phase 4) ──
341	            // Phase 4 will replace this with a real lookup when a Signal
342	            // Contract exists for the top_action. Phase 6's instrument.py
343	            // uses this to decide whether to use the contract or fall back
344	            // to Causal Graph Tracking.
345	            signal_contract: null,
346	        });
347	    } catch (err: any) {
348	        console.error('[get-scores] Error:', err.message);
349	        return c.json(
350	            { error: 'Scoring service error', details: err.message, code: 'SCORING_ERROR', signal_contract: null },
351	            500
352	        );
353	    }
354	});
355

1	/**
2	 * Layerinfinite — routes/get-patterns.ts
3	 * GET /v1/get-patterns
4	 * ══════════════════════════════════════════════════════════════
5	 * Returns the most successful action sequences (episodes)
6	 * for a given context. Powers "pattern-based recommendations"
7	 * which go beyond single-action scoring by returning whole
8	 * playbooks (ordered sequences of actions that resolved issues).
9	 * Reads from mv_episode_patterns (refreshed nightly).
10	 * ══════════════════════════════════════════════════════════════
11	 */
12	
13	import { Hono } from 'hono';
14	import { supabase } from '../lib/supabase.js';
15	
16	export const getPatternsRouter = new Hono();
17	
18	// ── GET /v1/get-patterns ──────────────────────────────────────
19	getPatternsRouter.get('/', async (c) => {
20	    const customerId = c.get('customer_id') as string;
21	
22	    const issueType = c.req.query('issue_type');
23	    const contextId = c.req.query('context_id');
24	    const minSamples = parseInt(c.req.query('min_samples') ?? '2', 10);
25	    const topN = parseInt(c.req.query('top_n') ?? '5', 10);
26	
27	    if (!issueType && !contextId) {
28	        return c.json(
29	            { error: 'Provide either issue_type or context_id', code: 'MISSING_PARAM' },
30	            400
31	        );
32	    }
33	
34	    // ── Resolve context_id ────────────────────────────────────
35	    let resolvedContextId = contextId;
36	
37	    if (!resolvedContextId && issueType) {
38	        const { data, error } = await supabase
39	            .from('dim_contexts')
40	            .select('context_id')
41	            .eq('issue_type', issueType)
42	            .limit(1)
43	            .maybeSingle();
44	
45	        if (error) {
46	            return c.json({ error: 'Context lookup failed', details: error.message }, 500);
47	        }
48	        if (!data) {
49	            return c.json(
50	                {
51	                    patterns: [],
52	                    total_found: 0,
53	                    context_id: null,
54	                    issue_type: issueType,
55	                    message: `No patterns yet for "${issueType}". Patterns appear after 2+ complete episodes.`,
56	                    cold_start: true,
57	                },
58	                200
59	            );
60	        }
61	        resolvedContextId = data.context_id;
62	    }
63	
64	    // ── Fetch patterns from materialized view ─────────────────
65	    const { data: patterns, error } = await supabase
66	        .from('mv_episode_patterns')
67	        .select('*')
68	        .eq('customer_id', customerId)
69	        .eq('context_id', resolvedContextId)
70	        .gte('sample_count', minSamples)
71	        .gte('episode_success_rate', 0.5)     // only show patterns with >50% success
72	        .order('episode_success_rate', { ascending: false })
73	        .limit(Math.min(topN, 20));
74	
75	    if (error) {
76	        return c.json({ error: 'Pattern query failed', details: error.message, code: 'DB_ERROR' }, 500);
77	    }
78	
79	    if (!patterns || patterns.length === 0) {
80	        return c.json({
81	            patterns: [],
82	            total_found: 0,
83	            context_id: resolvedContextId,
84	            issue_type: issueType ?? null,
85	            message: 'No patterns found yet. Patterns appear after 2+ complete episodes with shared action sequences.',
86	            cold_start: true,
87	        }, 200);
88	    }
89	
90	    // ── Enrich action_sequence with names ─────────────────────
91	    // action_sequence is stored as [{action_id, success, ...}, ...]
92	    // Batch-resolve action names from dim_actions
93	    const allActionIds = new Set<string>();
94	    patterns.forEach((p: any) => {
95	        const seq = p.action_sequence ?? [];
96	        seq.forEach((step: any) => {
97	            if (step?.action_id) allActionIds.add(step.action_id);
98	        });
99	    });
100	
101	    let actionNameMap: Record<string, string> = {};
102	    if (allActionIds.size > 0) {
103	        const { data: actions } = await supabase
104	            .from('dim_actions')
105	            .select('action_id, action_name')
106	            .in('action_id', Array.from(allActionIds));
107	
108	        if (actions) {
109	            actionNameMap = Object.fromEntries(actions.map((a: any) => [a.action_id, a.action_name]));
110	        }
111	    }
112	
113	    const enriched = patterns.map((p: any) => ({
114	        context_id: p.context_id,
115	        customer_id: p.customer_id,
116	        episode_success_rate: p.episode_success_rate,
117	        avg_duration_ms: p.avg_duration_ms,
118	        sample_count: p.sample_count,
119	        last_seen_at: p.last_seen_at,
120	        view_refreshed_at: p.view_refreshed_at,
121	        action_sequence: (p.action_sequence ?? []).map((step: any) => ({
122	            ...step,
123	            action_name: actionNameMap[step?.action_id] ?? step?.action_id,
124	        })),
125	    }));
126	
127	    return c.json({
128	        patterns: enriched,
129	        total_found: enriched.length,
130	        context_id: resolvedContextId,
131	        issue_type: issueType ?? null,
132	        cold_start: false,
133	    });
134	});
