182	function computeSalience(
183	    actionId: string,
184	    contextId: string,
185	    customerId: string,
186	    success: boolean
187	): number {
188	    const cachedScore = getCachedScore(actionId, contextId, customerId);
189	    if (cachedScore !== null && cachedScore > 0.9 && success) {
190	        return 0.1;
191	    }
192	    return 1.0;
