325	// ── FIX 2: resolveContextId now accepts and uses customerId ────
326	// BEFORE: context was looked up only by (issue_type, environment).
327	// This caused ALL customers with the same issue_type to share one
328	// context_id row, meaning Customer A's outcome scores bled into
329	// Customer B's recommendations — a complete multi-tenancy failure.
330	//
331	// AFTER: every SELECT and INSERT is scoped by customer_id.
332	// Each customer gets their own context row per (issue_type, environment).
333	// This means dim_contexts grows by (unique customers × unique issue_types)
334	// which is expected and correct — the composite unique index on
335	// (customer_id, issue_type, environment) prevents duplicates.
336	async function resolveContextId(body: any, customerId: string): Promise<string> {
337	    const { data: existingCtx } = await supabase
338	        .from('dim_contexts')
339	        .select('context_id')
340	        .eq('customer_id', customerId)       // ← FIX: scope by customer
341	        .eq('issue_type', body.issue_type)
342	        .eq('environment', body.environment)
343	        .maybeSingle();
344	
345	    if (existingCtx?.context_id) return existingCtx.context_id;
346	
347	    const { data: newCtx, error: ctxErr } = await supabase
348	        .from('dim_contexts')
349	        .insert({
350	            customer_id: customerId,           // ← FIX: always store customer
351	            issue_type: body.issue_type,
352	            environment: body.environment,
353	            customer_tier: body.customer_tier ?? null,
354	        })
355	        .select('context_id')
356	        .single();
357	
358	    if (ctxErr || !newCtx?.context_id) {
359	        throw new Error(`CONTEXT_ERROR:${ctxErr?.message || 'Missing context_id'}`);
360	    }
361	    return newCtx.context_id;
362	}
