364	async function insertCoreOutcome(
365	    agentId: string, customerId: string, actionId: string, contextId: string,
366	    body: any, finalSuccess: boolean, finalOutcomeScore: number | null, verification: any
367	) {
368	    // RULE: backprop_episode_id is INTERNAL — set by the backprop engine only.
369	    // NEVER map body.episode_id to this column. body.episode_id is the SDK's
370	    // sequence-tracking field; backprop_episode_id has a FK to fact_episodes which
371	    // only the backprop engine populates. Passing body.episode_id here causes FK
372	    // violation 23503 on every request that sends episode_id.
373	    const { data: outcome, error: insertErr } = await supabase
374	        .from('fact_outcomes')
375	        .insert({
376	            agent_id: agentId,
377	            action_id: actionId,
378	            context_id: contextId,
379	            customer_id: customerId,
380	            session_id: body.session_id,
381	            success: finalSuccess,
382	            response_time_ms: body.response_time_ms ?? null,
383	            error_code: body.error_code ?? null,
384	            error_message: body.error_message ?? null,
385	            raw_context: body.raw_context ?? {},
386	            is_synthetic: false,
387	            salience_score: computeSalience(actionId, contextId, customerId, finalSuccess),
388	            outcome_score: finalOutcomeScore,
389	            business_outcome: body.business_outcome ?? null,
390	            feedback_signal: body.feedback_signal ?? 'immediate',
391	            verifier_source: body.verifier_signal?.source ?? null,
392	            verifier_value: body.verifier_signal?.value?.toString() ?? null,
393	            discrepancy_detected: verification.discrepancy_detected,
394	            backprop_episode_id: body.backprop_episode_id ?? null,
395	            // episode_id: the SDK's sequence-grouping field.
396	            // Stored as plain UUID string — no FK constraint.
397	            // Distinct from backprop_episode_id which has a FK to fact_episodes.
398	            episode_id: body.episode_id ?? null,
399	            // ── Phase 1: Signal columns ───────────────────────
400	            signal_source: body.signal_source ?? 'explicit',
401	            signal_confidence: body.causal_confidence ?? null,
402	            causal_depth: body.signal_depth ?? null,
403	            signal_pending: false,
404	            signal_updated_at: null,
405	        })
406	        .select('outcome_id, timestamp')
407	        .single();
408	
409	    if (insertErr || !outcome) throw new Error(`INSERT_ERROR:${insertErr?.message}`);
410	    return outcome;
411	}
