437	
438	        if (decErr || !decision) {
439	            console.warn('[log-outcome] decision_id not found:', body.decision_id);
440	            return null;
441	        }
442	        if (decision.agent_id && decision.agent_id !== agentId) {
443	            throw new Error('DECISION_AGENT_MISMATCH');
444	        }
445	
446	        await supabase
447	            .from('fact_decisions')
448	            .update({
449	                chosen_action_name: body.action_name,
450	                chosen_action_id: actionId,
451	                outcome_id: outcomeId,
452	                resolved_at: new Date().toISOString(),
453	            })
454	            .eq('id', body.decision_id);
455	
456	        return decision;
457	    } catch (err: any) {
458	        if (err.message === 'DECISION_AGENT_MISMATCH') throw err;
459	        console.warn('[log-outcome] decision resolution error:', err.message);
460	        return null;
461	    }
462	}
463	
464	async function computePolicyRecommendation(
465	    customerId: string, contextId: string, agentId: string, issueType: string
466	): Promise<{ policy: ReturnType<typeof getPolicyDecision>; trust: AgentTrustScore } | null> {
467	    try {
468	        const [scores, agentTrust, customerConfig] = await Promise.all([
469	            getScores(customerId, contextId, issueType, false),
470	            getAgentTrust(agentId),
471	            getCustomerConfig(customerId),
472	        ]);
473	        const policy = getPolicyDecision({
474	            rankedActions: scores.ranked_actions,
475	            agentTrust,
476	            customerConfig,
477	            coldStartActive: scores.cold_start,
478	        });
479	        return { policy, trust: agentTrust };
480	    } catch {
481	        return null;
482	    }
483	}
484	
485	// ── MAIN ORCHESTRATOR ──
486	logOutcomeRouter.post('/', async (c) => {
487	    const agentId = c.get('agent_id') as string;
488	    const customerId = c.get('customer_id') as string;
489	
490	    if (!customerId) {
491	        return c.json({ error: 'Missing customer context', code: 'MISSING_CUSTOMER_ID' }, 401);
492	    }
493	
494	    try {
495	        // 1. Parsing & Sanitization
496	        const body = await parseAndSanitizeRequest(c);
497	
498	        // 2. Idempotency Check
499	        const originalOutcome = await handleIdempotency(body.idempotency_key);
500	        if (originalOutcome) {
501	            c.header('Idempotent-Replayed', 'true');
502	            return c.json({
503	                success: originalOutcome.success,
504	                outcome_id: originalOutcome.outcome_id,
505	                action_id: originalOutcome.action_id,
506	                context_id: originalOutcome.context_id,
507	                timestamp: originalOutcome.timestamp,
508	                message: `Outcome previously logged (idempotent replay). Action "${body.action_name}" — ${originalOutcome.success ? 'SUCCESS' : 'FAILURE'}`,
509	                idempotency_replayed: true,
510	            }, 200);
511	        }
512	
513	        // 3. Verification Layer
514	        const verification = await verifyOutcome(body, customerId, agentId);
515	        const finalSuccess = verification.verified_success;
516	        const finalOutcomeScore = verification.confidence_override ?? body.outcome_score ?? null;
517	
518	        // 4. Resolve References
519	        const actionId = await resolveActionId(c, body, customerId);
520	        const contextId = await resolveContextId(body, customerId); // ← FIX: pass customerId
521	
522	        // 5. Insert Core Fact
523	        const outcome = await insertCoreOutcome(agentId, customerId, actionId, contextId, body, finalSuccess, finalOutcomeScore, verification);
524	
525	        // 6. Post-Insert Synchronous Updates
526	        await saveIdempotencyRecord(body.idempotency_key, outcome.outcome_id);
527	        invalidateCache(customerId, contextId);
528	        const decisionRecord = await resolveDecisionId(body, agentId, actionId, outcome.outcome_id);
529	
530	        // 7. Fire-and-forget Asynchronous Pipelines via Orchestrator
531	        orchestrateOutcome({
532	            agentId, customerId, outcomeId: outcome.outcome_id, actionId, actionName: body.action_name ?? 'unknown',
533	            contextId, issueType: body.issue_type, finalSuccess, finalOutcomeScore,
534	            responseMs: body.response_time_ms ?? null, episodeId: body.episode_id,
535	            businessOutcome: body.business_outcome, decisionId: body.decision_id, decisionRecord,
536	            signalConfidence: body.causal_confidence ?? null,
537	        }).catch(err => console.error('[log-outcome] orchestrator failed:', { error: err.message, outcomeId: outcome.outcome_id }));
538	
539	        // 8. Policy Engine Wrap-up
540	        const policyResultData = await computePolicyRecommendation(customerId, contextId, agentId, body.issue_type);
541	        const policyResult = policyResultData?.policy ?? null;
542	        const agentTrust = policyResultData?.trust ?? LOCAL_DEFAULT_TRUST;
543	        const finalValidatedAction = c.get('validated_action') as any;
544	
545	        const counterfactualsComputed = !!(decisionRecord?.ranked_actions);
546	        const sequencePosition = body.episode_id ? (body.episode_history ? body.episode_history.length : 0) : null;
547	
548	        return c.json({
549	            success: true,
550	            outcome_id: outcome.outcome_id,
551	            action_id: actionId,
552	            context_id: contextId,
553	            timestamp: outcome.timestamp,
554	            message: `Outcome logged. Action "${body.action_name ?? 'unknown'}" — ${finalSuccess ? 'SUCCESS' : 'FAILURE'}`,
555	            // ── SDK required response fields ──────────────────
556	            logged: true,
557	            agent_trust_score: agentTrust.trust_score,
558	            trust_status: agentTrust.trust_status,
559	            policy: policyResult?.policy ?? 'explore',
560	            recommendation: policyResult?.policy ?? null,
561	            next_actions: policyResult ? {
562	                policy: policyResult.policy, reason: policyResult.reason,
563	                selected_action: policyResult.selectedAction, exploration_target: policyResult.explorationTarget,
564	            } : null,
565	            counterfactuals_computed: counterfactualsComputed,
566	            sequence_position: sequencePosition,
567	            idempotency_replayed: false,
568	            validation_warnings: finalValidatedAction?.validation_warnings ?? [],
569	        }, 201);
570	
571	    } catch (err: any) {
572	        if (err.message === 'PAYLOAD_TOO_LARGE') {
573	            return c.json({ error: 'PAYLOAD_TOO_LARGE', message: 'raw_context exceeds 64KB limit' }, 413);
574	        }
575	        if (err.message === 'CONFLICT') {
576	            return c.json({ error: 'Duplicate idempotency_key — this outcome was already logged. Pass the same key to retrieve the original outcome_id.', code: 'CONFLICT' }, 409);
577	        }
578	        if (err.message === 'DECISION_AGENT_MISMATCH') {
579	            return c.json({ error: 'decision_id belongs to a different agent', code: 'DECISION_AGENT_MISMATCH' }, 400);
580	        }
581	        if (err.message.startsWith('UNKNOWN_ACTION:')) {
582	            const parts = err.message.split(':');
583	            return c.json({ error: parts[1], message: parts[2] }, 400);
584	        }
585	        if (err.message.startsWith('VALIDATION_ERROR:')) {
586	            return c.json({ error: 'Invalid request body', details: err.message.substring(17), code: 'VALIDATION_ERROR' }, 400);
587	        }
588	        if (err.message.startsWith('CONTEXT_ERROR:')) {
589	            return c.json({ error: 'Failed to resolve context', details: err.message.substring(14), code: 'CONTEXT_ERROR' }, 500);
590	        }
591	        if (err.message.startsWith('INSERT_ERROR:')) {
592	            return c.json({ error: 'Failed to log outcome', details: err.message.substring(13), code: 'INSERT_ERROR' }, 500);
593	        }
594	        return c.json({ error: 'Internal server error', details: err.message }, 500);
595	    }
596	});

1	/**
2	 * Layerinfinite — routes/outcome-feedback.ts
3	 * POST /v1/outcome-feedback
4	 * ══════════════════════════════════════════════════════════════
5	 * Accepts delayed outcome feedback — submitted hours/days after
6	 * the original outcome was logged.
7	 *
8	 * This is the ONE permitted UPDATE path on fact_outcomes.
9	 * Only outcome_score, business_outcome, and feedback_received_at
10	 * are modified. All other columns remain immutable.
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	import { Hono } from 'hono';
15	import { z } from 'zod';
16	import { supabase } from '../lib/supabase.js';
17	import { invalidateCache } from '../lib/scoring.js';
18	
19	export const outcomeFeedbackRouter = new Hono();
20	
21	const FeedbackBody = z.object({
22	    outcome_id: z.string().uuid(),
23	    final_score: z.number().min(0.0).max(1.0),
24	    // Any string is accepted. Values are normalized to the four canonical
25	    // labels at the application layer. Unknown values map to 'unknown'.
26	    // Field is metadata-only — never read by scoring, trust, or policy.
27	    business_outcome: z
28	        .string()
29	        .min(1)
30	        .max(100)
31	        .transform(val => {
32	            const normalized = val.trim().toLowerCase();
33	            const known = ['resolved', 'partial', 'failed', 'unknown'] as const;
34	            return (known as readonly string[]).includes(normalized)
35	                ? (normalized as typeof known[number])
36	                : 'unknown';
37	        }),
38	    feedback_notes: z.string().max(2000).optional(),
39	});
40	
41	outcomeFeedbackRouter.post('/', async (c) => {
42	    const customerId = c.get('customer_id') as string;
43	
44	    let body: z.infer<typeof FeedbackBody>;
45	    try {
46	        body = FeedbackBody.parse(await c.req.json());
47	    } catch (err: any) {
48	        return c.json(
49	            { error: 'Invalid request body', details: err.errors ?? err.message, code: 'VALIDATION_ERROR' },
50	            400
51	        );
52	    }
53	
54	    // ── Verify outcome belongs to this customer ──────────────
55	    const { data: outcome, error: lookupErr } = await supabase
56	        .from('fact_outcomes')
57	        .select('outcome_id, customer_id, context_id')
58	        .eq('outcome_id', body.outcome_id)
59	        .maybeSingle();
60	
61	    if (lookupErr) {
62	        return c.json({ error: 'Lookup failed', details: lookupErr.message }, 500);
63	    }
64	
65	    if (!outcome || outcome.customer_id !== customerId) {
66	        return c.json({ error: 'Outcome not found', code: 'NOT_FOUND' }, 404);
67	    }
68	
69	    // ── Insert feedback record ───────────────────────────────
70	    const { error: feedbackErr } = await supabase
71	        .from('fact_outcome_feedback')
72	        .insert({
73	            outcome_id: body.outcome_id,
74	            customer_id: customerId,
75	            final_score: body.final_score,
76	            business_outcome: body.business_outcome,
77	            feedback_notes: body.feedback_notes ?? null,
78	        });
79	
80	    if (feedbackErr) {
81	        return c.json({ error: 'Failed to store feedback', details: feedbackErr.message }, 500);
82	    }
83	
84	    // ── Update fact_outcomes with final score ────────────────
85	    // This is the ONE permitted UPDATE on fact_outcomes.
86	    // The prevent_outcome_update trigger allows changes ONLY to
87	    // outcome_score, business_outcome, and feedback_received_at.
88	    const { error: updateErr } = await supabase
89	        .from('fact_outcomes')
90	        .update({
91	            outcome_score: body.final_score,
92	            business_outcome: body.business_outcome,
93	            feedback_received_at: new Date().toISOString(),
94	        })
95	        .eq('outcome_id', body.outcome_id);
96	
97	    if (updateErr) {
98	        return c.json({ error: 'Failed to update outcome', details: updateErr.message }, 500);
99	    }
100	
101	    // ── Trigger score cache refresh (async, non-blocking) ────
102	    invalidateCache(customerId, outcome.context_id);
103	
104	    // ── DELAYED SILENT FAILURE DETECTION (Gap 5) ─────────────
105	    // Original outcome was success=true but feedback shows low score.
106	    (async () => {
107	        const { data: original } = await supabase
108	            .from('fact_outcomes')
109	            .select('success, action_id, agent_id')
110	            .eq('outcome_id', body.outcome_id)
111	            .single();
112	
113	        const isDelayedSilentFailure =
114	            original?.success === true &&
115	            body.final_score < 0.3;
116	
117	        if (isDelayedSilentFailure) {
118	            await supabase.from('degradation_alert_events').insert({
119	                customer_id: customerId,
120	                action_id: original.action_id,
121	                alert_type: 'degradation',
122	                severity: 'warning',
123	                current_value: body.final_score,
124	                baseline_value: 1.0,
125	                message: `Delayed silent failure confirmed: "${body.business_outcome}" — originally logged as success, final score: ${body.final_score}. ${body.feedback_notes || ''}`,
126	            });
127	        }
128	    })().catch(err => {
129	        console.warn('[outcome-feedback] Delayed silent failure check failed:', err);
130	    });
131	
132	    return c.json({
133	        updated: true,
134	        outcome_id: body.outcome_id,
135	        final_score: body.final_score,
136	        business_outcome: body.business_outcome,
137	    });
138	});
