1	/**
2	 * Layerinfinite — middleware/auth.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * API key authentication middleware for Hono.
5	 *
6	 * Validates X-API-Key → agent lookup in dim_agents.
7	 * Sets: agent_id, customer_id, agent_name, customer_tier
8	 *
9	 * DEV BYPASS: Only active when BOTH conditions are met:
10	 *   NODE_ENV === 'development' AND LAYERINFINITE_DEV_BYPASS === 'true'
11	 * If LAYERINFINITE_DEV_BYPASS=true in production → hard crash (refuse to start).
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Context, Next } from 'hono';
16	import crypto from 'node:crypto';
17	import { supabase } from '../lib/supabase.js';
18	
19	// TTL reduced to 60s for security:
20	// Revoked keys must be rejected within 1 minute.
21	// PERFORMANCE NOTE: At 1000 req/min (enterprise tier),
22	// 60s TTL = ~16.7 DB auth reads/sec worst case
23	// (assumes zero cache hits on new keys).
24	// Benchmark with k6 before enterprise onboarding.
25	// Consider per-tier TTL (free=60s, pro=120s, enterprise=300s)
26	// if auth becomes a DB bottleneck under load.
27	// The 15-min cache was premature optimization at the
28	// expense of security — do not revert without load data.
29	const AUTH_CACHE_TTL_MS = 60 * 1000;
30	
31	interface AgentAuth {
32	    agent_id: string;
33	    customer_id: string;
34	    agent_name: string;
35	    agent_type: string;
36	    llm_model: string | null;
37	    customer_tier: string;
38	    expires_at: number;
39	}
40	
41	const authCache = new Map<string, AgentAuth>();
42	
43	// Evict expired entries every 5 minutes
44	const CLEANUP_INTERVAL_MS = 5 * 60_000;
45	setInterval(() => {
46	    const now = Date.now();
47	    let evicted = 0;
48	    for (const [key, entry] of authCache.entries()) {
49	        if (entry.expires_at < now) {
50	            authCache.delete(key);
51	            evicted++;
52	        }
53	    }
54	    if (evicted > 0) {
55	        console.info(`[cache-cleanup] Evicted ${evicted} expired entries from authCache`);
56	    }
57	}, CLEANUP_INTERVAL_MS).unref();
58	
59	setInterval(() => {
60	    console.info(`[cache-size] authCache: ${authCache.size} entries`);
61	}, 15 * 60_000).unref();
62	
63	// AUTH RULE: This middleware accepts ONLY agent API keys (format: layerinfinite_XXXX).
64	// Supabase JWTs (format: eyJhbG...) are NOT valid here and return a 400 with a
65	// helpful error. Dashboard pages MUST use useAgentApiKey() hook, never getSession().
66	
67	/**
68	 * Hashes an incoming API key to compare against database records.
69	 *
70	 * Algorithm: SHA-256
71	 * Rationale: MD5 is cryptographically broken. bcrypt is strictly for passwords
72	 *   because its intentional slowness causes DoS vulnerabilities on API limits.
73	 *   HMAC-SHA256 (or fast SHA-256) is industry standard for API token validation.
74	 * Date of fix: 2026-03-14
75	 */
76	function hashKey(apiKey: string): string {
77	    return crypto.createHash('sha256').update(apiKey).digest('hex');
78	}
79	
80	export function invalidateAuthCacheByAgentId(agentId: string) {
81	    for (const [key, val] of authCache.entries()) {
82	        if (val.agent_id === agentId) {
83	            authCache.delete(key);
84	        }
85	    }
86	}
87	
88	export async function authMiddleware(c: Context, next: Next): Promise<Response | void> {
89	    // ── DEV BYPASS — NEVER active in production ────────────────
90	    if (process.env.NODE_ENV === 'development' &&
91	        process.env.LAYERINFINITE_DEV_BYPASS === 'true') {
92	        console.warn('⚠️  DEV BYPASS ACTIVE — NEVER deploy with this enabled');
93	        c.set('agent_id', process.env.DEV_AGENT_ID ?? 'd0000000-0000-0000-0000-000000000001');
94	        c.set('customer_id', process.env.DEV_CUSTOMER_ID ?? 'a0000000-0000-0000-0000-000000000001');
95	        c.set('agent_name', 'dev-bypass-agent');
96	        c.set('customer_tier', 'enterprise');
97	        await next();
98	        return;
99	    }
100	
101	    const apiKey = c.req.header('X-API-Key') ?? c.req.header('Authorization')?.replace('Bearer ', '');
102	
103	    if (!apiKey) {
104	        return c.json(
105	            { error: 'Missing API key. Provide X-API-Key header.', code: 'MISSING_API_KEY' },
106	            401
107	        );
108	    }
109	
110	    // Detect Supabase JWT tokens sent by mistake — give a helpful error instead of
111	    // silently failing with INVALID_API_KEY (which is confusing for dashboard users).
112	    if (apiKey.startsWith('eyJ')) {
113	        return c.json(
114	            {
115	                error: 'JWT tokens are not valid for agent API routes. Use your agent API key.',
116	                hint: 'Find your API key in Settings → API Keys',
117	                code: 'WRONG_AUTH_TYPE',
118	            },
119	            400
120	        );
121	    }
122	
123	    // Check cache first
124	    const cached = authCache.get(hashKey(apiKey));
125	    if (cached && cached.expires_at > Date.now()) {
126	        c.set('agent_id', cached.agent_id);
127	        c.set('customer_id', cached.customer_id);
128	        c.set('agent_name', cached.agent_name);
129	        c.set('customer_tier', cached.customer_tier);
130	        await next();
131	        return;
132	    }
133	
134	    // Validate against database — join dim_customers for tier
135	    const { data, error } = await supabase
136	        .from('dim_agents')
137	        .select(`
138	            agent_id, customer_id, agent_name, agent_type, llm_model,
139	            is_active, api_key_hash,
140	            dim_customers!inner(tier)
141	        `)
142	        .eq('api_key_hash', hashKey(apiKey))
143	        .eq('is_active', true)
144	        .maybeSingle();
145	
146	    if (error) {
147	        console.error('[auth] DB error:', error.message);
148	        return c.json({ error: 'Authentication service unavailable', code: 'AUTH_ERROR' }, 503);
149	    }
150	
151	    if (!data) {
152	        return c.json(
153	            { error: 'Invalid or inactive API key', code: 'INVALID_API_KEY' },
154	            401
155	        );
156	    }
157	
158	    const customerTier = (data as any).dim_customers?.tier ?? 'pro';
159	
160	    // Cache the result
161	    authCache.set(hashKey(apiKey), {
162	        agent_id: data.agent_id,
163	        customer_id: data.customer_id,
164	        agent_name: data.agent_name,
165	        agent_type: data.agent_type,
166	        llm_model: data.llm_model,
167	        customer_tier: customerTier,
168	        expires_at: Date.now() + AUTH_CACHE_TTL_MS,
169	    });
170	
171	    c.set('agent_id', data.agent_id);
172	    c.set('customer_id', data.customer_id);
173	    c.set('agent_name', data.agent_name);
174	    c.set('customer_tier', customerTier);
175	
176	    await next();
177	}
178	
179	/**
180	 * Development auth: accepts the service role key as the API key.
181	 * ONLY active when NODE_ENV !== 'production'.
182	 * Injects the demo agent/customer for testing.
183	 */
184	export async function devAuthMiddleware(c: Context, next: Next): Promise<Response | void> {
185	    if (process.env.NODE_ENV === 'production') {
186	        return authMiddleware(c, next);
187	    }
188	
189	    const apiKey = c.req.header('X-API-Key') ?? c.req.header('Authorization')?.replace('Bearer ', '');
190	
191	    if (!apiKey && process.env.NODE_ENV !== 'production') {
192	        return c.json(
193	            { error: 'Missing API key. Set X-API-Key header. For dev: set LAYERINFINITE_DEV_API_KEY env var.', code: 'MISSING_API_KEY' },
194	            401
195	        );
196	    }
197	
198	    if (apiKey && apiKey === process.env.LAYERINFINITE_DEV_API_KEY) {
199	        // Inject demo agent — ONLY in development
200	        c.set('agent_id', 'd0000000-0000-0000-0000-000000000001');
201	        c.set('customer_id', 'a0000000-0000-0000-0000-000000000001');
202	        c.set('agent_name', 'payment-bot-1 (dev)');
203	        c.set('customer_tier', 'enterprise');
204	        await next();
205	        return;
206	    }
207	
208	    return authMiddleware(c, next);
209	}
