1	/**
2	 * Layerinfinite — routes/admin/reinstate-agent.ts
3	 * POST /v1/admin/reinstate-agent
4	 * ══════════════════════════════════════════════════════════════
5	 * Reinstates a suspended agent to probation status.
6	 * Sets trust_score=0.4, trust_status='probation',
7	 * consecutive_failures=0, and logs to agent_trust_audit.
8	 * ══════════════════════════════════════════════════════════════
9	 */
10	
11	import { Hono } from 'hono';
12	import { z } from 'zod';
13	import { supabase } from '../../lib/supabase.js';
14	
15	export const reinstateAgentRouter = new Hono();
16	
17	const ReinstateBody = z.object({
18	    agent_id: z.string().uuid(),
19	    reinstated_by: z.string().min(1).max(255),
20	});
21	
22	reinstateAgentRouter.post('/', async (c) => {
23	    const customerId = c.get('customer_id') as string;
24	
25	    let body: z.infer<typeof ReinstateBody>;
26	    try {
27	        body = ReinstateBody.parse(await c.req.json());
28	    } catch (err: any) {
29	        return c.json({ error: 'Invalid request body', details: err.errors ?? err.message }, 400);
30	    }
31	
32	    // ── Verify agent belongs to this customer ──────────────────
33	    const { data: agent, error: agentErr } = await supabase
34	        .from('dim_agents')
35	        .select('agent_id, agent_name, customer_id')
36	        .eq('agent_id', body.agent_id)
37	        .eq('customer_id', customerId)
38	        .maybeSingle();
39	
40	    if (agentErr) {
41	        return c.json({ error: 'Agent lookup failed', details: agentErr.message }, 500);
42	    }
43	    if (!agent) {
44	        return c.json({ error: 'Agent not found or does not belong to your account', code: 'NOT_FOUND' }, 404);
45	    }
46	
47	    // ── Verify agent is currently suspended ────────────────────
48	    const { data: trust, error: trustErr } = await supabase
49	        .from('agent_trust_scores')
50	        .select('trust_score, trust_status, consecutive_failures')
51	        .eq('agent_id', body.agent_id)
52	        .maybeSingle();
53	
54	    if (trustErr) {
55	        return c.json({ error: 'Trust lookup failed', details: trustErr.message }, 500);
56	    }
57	
58	    if (!trust || trust.trust_status !== 'suspended') {
59	        return c.json(
60	            { error: 'Agent is not currently suspended', code: 'INVALID_STATE', current_status: trust?.trust_status ?? 'unknown' },
61	            400
62	        );
63	    }
64	
65	    // ── Reinstate: update trust scores ─────────────────────────
66	    const { error: updateErr } = await supabase
67	        .from('agent_trust_scores')
68	        .update({
69	            trust_score: 0.4,
70	            trust_status: 'probation',
71	            consecutive_failures: 0,
72	            updated_at: new Date().toISOString(),
73	        })
74	        .eq('agent_id', body.agent_id);
75	
76	    if (updateErr) {
77	        return c.json({ error: 'Failed to reinstate agent', details: updateErr.message }, 500);
78	    }
79	
80	    // ── Log to agent_trust_audit ───────────────────────────────
81	    await supabase
82	        .from('agent_trust_audit')
83	        .insert({
84	            agent_id: body.agent_id,
85	            customer_id: customerId,
86	            event_type: 'reinstated',
87	            old_score: trust.trust_score,
88	            new_score: 0.4,
89	            old_status: 'suspended',
90	            new_status: 'probation',
91	            performed_by: body.reinstated_by,
92	            reason: `Manually reinstated by ${body.reinstated_by}`,
93	        });
94	
95	    return c.json({
96	        reinstated: true,
97	        agent_id: body.agent_id,
98	        agent_name: agent.agent_name,
99	        new_status: 'probation',
100	        new_score: 0.4,
101	        message: `Agent "${agent.agent_name}" reinstated to probation (score: 0.4).`,
102	    }, 200);
103	});
