38	function computeContextHash(context: Record<string, unknown>): string {
39	  // Use issue_type if present (most common pattern)
40	  const issueType = context.issue_type ?? context.context_type ?? '';
41	  const contextId = context.context_id ?? '';
42	  if (contextId) {
43	    return `${contextId}:${issueType}`;
44	  }
45	  // Fallback: stable JSON key — deterministic across calls
46	  const keys = Object.keys(context).sort();
47	  const stable = keys.map((k) => `${k}=${JSON.stringify(context[k])}`).join('|');
48	  return stable;
49	}
50	
51	// ── POST /v1/simulate ─────────────────────────────────────────
52	simulateRouter.post('/', async (c) => {
53	  // Parse and validate body
54	  let body: z.infer<typeof SimulateBody>;
55	  try {
56	    const raw = await c.req.json();
57	    body = SimulateBody.parse(raw);
58	  } catch (err: any) {
59	    return c.json(
60	      {
61	        error: 'Invalid request body',
62	        details: err.errors ?? err.message,
63	        code: 'VALIDATION_ERROR',
64	        agent_id: '',
65	      },
66	      400,
67	    );
68	  }
69	
70	  const {
71	    agent_id,
72	    context,
73	    proposed_sequence,
74	    episode_history,
75	    simulate_alternatives,
76	    max_sequence_depth,
77	  } = body;
78	
79	  const customerId = c.get('customer_id') as string;
80	
81	  if (!customerId) {
82	    return c.json({ error: 'Missing agent context', code: 'MISSING_AGENT', agent_id: '' }, 401);
83	  }
84	
85	  const { data: agentRow, error: agentLookupError } = await supabase
86	    .from('dim_agents')
87	    .select('agent_id')
88	    .eq('agent_id', agent_id)
89	    .eq('customer_id', customerId)
90	    .maybeSingle();
91	
92	  if (agentLookupError) {
93	    return c.json({ error: 'Agent lookup failed', code: 'AGENT_LOOKUP_ERROR', agent_id }, 500);
94	  }
95	
96	  if (!agentRow) {
97	    return c.json({ error: 'Agent not found', code: 'NOT_FOUND', agent_id }, 404);
98	  }
99	
100	  // Compute context hash
101	  const contextHash = computeContextHash(context);
102	
103	  // Run simulation
104	  const result = await runSimulation({
105	    customerId: customerId,
106	    agentId: agent_id,
107	    context,
108	    contextHash,
109	    proposedSequence: proposed_sequence,
110	    episodeHistory: episode_history,
111	    simulateAlternatives: simulate_alternatives,
112	    maxSequenceDepth: max_sequence_depth,
113	  });
114	
115	  // Map to snake_case response (API convention)
116	  return c.json({
117	    primary: {
118	      actions: result.primary.actions,
119	      predicted_outcome: result.primary.predictedOutcome,
120	      outcome_interval_low: result.primary.outcomeIntervalLow,
121	      outcome_interval_high: result.primary.outcomeIntervalHigh,
122	      confidence_width: result.primary.confidenceWidth,
123	      confidence: result.primary.confidence,
124	      predicted_resolution: result.primary.predictedResolution,
125	      predicted_steps: result.primary.predictedSteps,
126	    },
127	    alternatives: result.alternatives.map((alt) => ({
128	      actions: alt.actions,
129	      predicted_outcome: alt.predictedOutcome,
130	      outcome_interval_low: alt.outcomeIntervalLow,
131	      outcome_interval_high: alt.outcomeIntervalHigh,
132	      confidence: alt.confidence,
133	      better_than_proposed: alt.betterThanProposed,
134	    })),
135	    simulation_tier: result.simulationTier,
136	    tier_explanation: result.tierExplanation,
137	    data_source: result.dataSource,
138	    episode_count: result.episodeCount,
139	    simulation_warning: result.simulationWarning,
140	  });
141	});
